// Pseudo-implementation
for (int i = 0; i < N_CHUNKS; ++i) {
LaunchKernel(ComputeStream, Chunks[i]);
if (i > 0) {
// Sync compute completion
EventRecord(ComputeStream, ev[i]);
StreamWaitEvent(CommStream, ev[i]);
// Async comm start
ncclAllReduce(Chunks[i], CommStream);
}
}
StreamSync(CommStream);
